def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.2:
            base_score = np.cos(ratio * 5) * (1 - ratio)**2 + np.sin(ratio * np.pi * 2)
        elif 0.2 <= ratio < 0.5:
            base_score = np.sqrt(ratio) * np.log1p(3 * ratio) - np.tanh(ratio * 4)
        elif 0.5 <= ratio < 0.8:
            base_score = 1 / (1 + np.exp(-20 * (ratio - 0.65))) + np.sin(ratio * 7) * np.cos(ratio * 3)
        else:
            base_score = np.tanh(15 * (ratio - 0.85)) + 1 / (1 + np.exp(5 * (ratio - 0.95)))
        penalty = 0
        for j in range(1, 8):
            val = (item * j) % capacity
            frac = val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.15:
                penalty += frac * 1.2
            elif 0.15 <= frac < 0.4:
                penalty += frac / (j**0.5)
            else:
                penalty += frac / (j + 2)
        extra_penalty = 0
        for k in range(1, 5):
            threshold = 0.4 * k
            if ratio > threshold:
                extra_penalty += np.exp(-k * ratio**1.5) * (k + 0.5)
            else:
                extra_penalty += np.log1p(k * ratio + 1.5) / (k + 1)
        adjustment_factor = 1 + (np.sin(capacity * 0.3) + np.cos(item * 0.7)) / 5
        if capacity % 3 == 0 and capacity % 2 != 0:
            final_score = base_score + penalty * 1.3 + extra_penalty * 0.9
        elif capacity % 5 == 0:
            final_score = base_score * 0.9 + penalty * 1.1 + extra_penalty * 1.2
        else:
            final_score = base_score + penalty + extra_penalty
        final_score *= adjustment_factor
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    return priorities
